// Calls: deadlineMonitorService.runDeadlineCheck()
// Checks overdue orders, slow purchases, calendar overload
const { runDeadlineCheck } = require('./app/js/tasks/deadlineMonitorService.js');
const result = runDeadlineCheck();
return [{ json: result }];

const { getOpenTasks } = require('./app/js/tasks/taskService.js');
const now = new Date();
const overdue = getOpenTasks().filter(t => t.due_at && new Date(t.due_at) < now);
return [{ json: { overdue, count: overdue.length } }];

const { sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const { overdue } = $input.first().json;
if (!overdue.length) return [];
const text = `⏰ Прострочені задачі (${overdue.length}):\n` + overdue.slice(0, 10).map(t => `• ${t.task_id}: ${t.title}`).join('\n');
await sendManagerAlert(text);
return $input.all();

// Calls: retryService.retryPendingOperations(handlerMap)
const { retryPendingOperations } = require('./app/js/utils/retryService.js');
// Register handlers for retryable operations
const handlerMap = {
  // Add operation handlers here as new features are added
